from cryptography.fernet import Fernet

# Function to generate and save a new encryption key
def generate_key():
    key = Fernet.generate_key()
    with open("secret.key", "wb") as key_file:
        key_file.write(key)

# Function to load the encryption key from a file
def load_key():
    return open("secret.key", "rb").read()

# Function to encrypt a credit card number
def encrypt_credit_card(card_number):
    key = load_key()
    fernet = Fernet(key)
    encrypted_card = fernet.encrypt(card_number.encode())
    return encrypted_card

# Function to decrypt a credit card number
def decrypt_credit_card(encrypted_card):
    key = load_key()
    fernet = Fernet(key)
    decrypted_card = fernet.decrypt(encrypted_card).decode()
    return decrypted_card

